-        uint32_t rB = *reinterpret_cast<uint32_t const*>(&sram.B[i]);
-        auto* rB_ptr = reinterpret_cast<input_t const*>(&rB);
-
-        uint32_t rC = *reinterpret_cast<uint32_t const*>(&sram.C[i]);
